Here is a clean reimplementation from scratch of what the obfuscated code is doing.

It simulates:

- a set of named nodes
- pairwise attraction between every node
- spring constraints between selected node pairs
- damping and weak pull toward the center
- a particle “stream” emitted from random nodes
- a smoothed camera state
- a fixed-timestep update loop

```javascript
class PhysicsSimulation {
  constructor() {
    this.TAU = Math.PI * 2;
    this.PHI = 1.618;
    this.SQRT_HALF = 0.707;

    this.config = {
      attraction: 4000,
      springCoefficient: 0.004,
      damping: 0.92,
      centerPull: 0.0003,
      maxParticles: 40,
      streamDecay: 0.04,
      cameraLerp: 0.06
    };

    this.nodes = [
      { id: "hub",     label: "Hub",     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
      { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
      { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
      { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
      { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
      { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
    ];

    this.springs = [
      { a: "hub",   b: "alpha",   rest: 160, k: 0.006 },
      { a: "hub",   b: "beta",    rest: 160, k: 0.005 },
      { a: "hub",   b: "gamma",   rest: 170, k: 0.004 },
      { a: "hub",   b: "delta",   rest: 170, k: 0.004 },
      { a: "hub",   b: "epsilon", rest: 180, k: 0.003 },
      { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
      { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
      { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
    ];

    this.camera = {
      x: 400,
      y: 300,
      zoom: 1
    };

    this.cameraTarget = {
      x: 400,
      y: 300,
      zoom: 1
    };

    this.particles = [];
    this.tickCount = 0;
    this.intervalId = null;
  }

  getNodeById(id) {
    return this.nodes.find(node => node.id === id) || null;
  }

  applyMutualAttraction() {
    for (let i = 0; i < this.nodes.length; i++) {
      for (let j = i + 1; j < this.nodes.length; j++) {
        const a = this.nodes[i];
        const b = this.nodes[j];

        const dx = a.x - b.x;
        const dy = a.y - b.y;
        const distance = Math.sqrt(dx * dx + dy * dy) || 1;

        const force = this.config.attraction / (distance * distance);
        const fx = (dx / distance) * force;
        const fy = (dy / distance) * force;

        a.vx += fx;
        a.vy += fy;
        b.vx -= fx;
        b.vy -= fy;
      }
    }
  }

  applySprings() {
    for (const spring of this.springs) {
      const a = this.getNodeById(spring.a);
      const b = this.getNodeById(spring.b);
      if (!a || !b) continue;

      const dx = b.x - a.x;
      const dy = b.y - a.y;
      const distance = Math.sqrt(dx * dx + dy * dy) || 1;

      const stretch = distance - spring.rest;
      const force = (spring.k ?? this.config.springCoefficient) * stretch;

      const fx = (dx / distance) * force;
      const fy = (dy / distance) * force;

      a.vx += fx;
      a.vy += fy;
      b.vx -= fx;
      b.vy -= fy;
    }
  }

  integrateNodes() {
    for (const node of this.nodes) {
      node.vx += (400 - node.x) * this.config.centerPull;
      node.vy += (300 - node.y) * this.config.centerPull;

      node.vx *= this.config.damping;
      node.vy *= this.config.damping;

      node.x += node.vx;
      node.y += node.vy;
    }
  }

  emitParticle() {
    if (this.particles.length >= this.config.maxParticles) return;

    const source = this.nodes[Math.floor(Math.random() * this.nodes.length)];
    const angle = Math.random() * this.TAU;
    const speed = 0.3 + Math.random() * this.SQRT_HALF;

    this.particles.push({
      x: source.x,
      y: source.y,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      age: 0,
      maxAge: 800 + Math.random() * 1200,
      size: 0.8 + (Math.random() * this.PHI) * this.SQRT_HALF
    });
  }

  updateParticles() {
    const drag = 1 - this.config.streamDecay * 0.125;

    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];

      p.age += 1;
      p.vx *= drag;
      p.vy *= drag;
      p.x += p.vx;
      p.y += p.vy;

      if (p.age > p.maxAge) {
        this.particles.splice(i, 1);
      }
    }
  }

  updateCamera() {
    this.camera.x += (this.cameraTarget.x - this.camera.x) * this.config.cameraLerp;
    this.camera.y += (this.cameraTarget.y - this.camera.y) * this.config.cameraLerp;
    this.camera.zoom += (this.cameraTarget.zoom - this.camera.zoom) * this.config.cameraLerp;
  }

  step() {
    this.applyMutualAttraction();
    this.applySprings();
    this.integrateNodes();
    this.updateParticles();
    this.updateCamera();

    if (this.tickCount % 3 === 0) {
      this.emitParticle();
    }

    this.tickCount += 1;
  }

  start(intervalMs = 10) {
    if (this.intervalId !== null) return;
    this.intervalId = setInterval(() => this.step(), intervalMs);
  }

  stop() {
    if (this.intervalId === null) return;
    clearInterval(this.intervalId);
    this.intervalId = null;
  }
}

// Example usage:
const simulation = new PhysicsSimulation();
simulation.start(10);
```

### What this code does
The original obfuscated script defines:

- constants and tuning parameters
- 6 nodes with initial positions:
  - hub
  - alpha
  - beta
  - gamma
  - delta
  - epsilon
- a set of spring links with rest lengths and stiffness
- a simple camera and camera target
- particle emission and decay
- an update loop every 10 ms

### Important behavioral details preserved
This version keeps the same behavior:

- **all nodes attract each other** with inverse-square force
- **springs** push/pull linked nodes toward rest distance
- **center pull** nudges all nodes toward `(400, 300)`
- **damping** reduces velocity every frame
- **particles** spawn from random nodes every third tick
- **camera** smoothly interpolates to its target

